pub async fn insert_user(pool: &sqlx::PgPool, name: &str, status: &UserStatus) -> Result<(), sqlx::Error> {
    sqlx::query!("INSERT INTO users (name, status) VALUES ($1, $2)", name, status as &UserStatus)
        .execute(pool)
        .await?;
    Ok(())
}

